2.14 迹 Trace
\[
\text{tr}(A) = \sum_{i=1}^n a_{ii}
\]

2.14.1 关键性质
\[
\text{tr}(AB) = \text{tr}(BA) \quad \text{（循环性质）}
\]
\[
\text{tr}(A) = \sum_{i=1}^n \lambda_i \quad \text{（迹 = 特征值之和）}
\]
\[
\det(A) = \prod_{i=1}^n \lambda_i \quad \text{（行列式 = 特征值之积）}
\]

2.14.1.1 代码表示：迹的计算与性质
练习：实现 trace(A, n)。验证 \(\text{tr}(AB) = \text{tr}(BA)\)、\(\text{tr}(A) = \sum \lambda_i\)、\(\|A\|_F = \sqrt{\text{tr}(A^TA)}\)。

#include &lt;stdio.h&gt;
#include &lt;math.h&gt;

double trace(const double* A, int n) {
    double s = 0.0;
    for (int i = 0; i &lt; n; i++)
        s += A[i * n + i];
    return s;
}

double det2x2(const double* A) {
    return A[0]*A[3] - A[1]*A[2];
}

void eigen2x2(const double* A, double* l1, double* l2) {
    double tr = A[0] + A[3];
    double det = A[0]*A[3] - A[1]*A[2];
    double disc = sqrt(tr*tr - 4*det);
    *l1 = (tr + disc) / 2.0;
    *l2 = (tr - disc) / 2.0;
}

int main() {
    double A[] = {2, 1,
                  1, 3};

    double l1, l2;
    eigen2x2(A, &l1, &l2);

    printf("A = [[2,1],[1,3]]\n\n");
    printf("tr(A)       = %.1f\n", trace(A, 2));
    printf("λ1 + λ2     = %.4f  (trace = sum of eigenvalues)\n", l1+l2);
    printf("\ndet(A)      = %.1f\n", det2x2(A));
    printf("λ1 × λ2     = %.4f  (det = product of eigenvalues)\n", l1*l2);

    // 验证循环性质: tr(AB) = tr(BA)
    double B[] = {5, 6, 7, 8};
    double AB[] = {A[0]*B[0]+A[1]*B[2], A[0]*B[1]+A[1]*B[3],
                   A[2]*B[0]+A[3]*B[2], A[2]*B[1]+A[3]*B[3]};
    double BA[] = {B[0]*A[0]+B[1]*A[2], B[0]*A[1]+B[1]*A[3],
                   B[2]*A[0]+B[3]*A[2], B[2]*A[1]+B[3]*A[3]};
    printf("\ntr(AB) = %.1f, tr(BA) = %.1f  (equal even though AB ≠ BA!)\n",
           trace(AB, 2), trace(BA, 2));

    // Frobenius norm: ||A||_F^2 = tr(A^T A)
    double AtA[] = {A[0]*A[0]+A[2]*A[2], A[0]*A[1]+A[2]*A[3],
                    A[0]*A[1]+A[2]*A[3], A[1]*A[1]+A[3]*A[3]};
    double frob = sqrt(trace(AtA, 2));
    printf("\n||A||_F = sqrt(tr(A^T A)) = %.4f\n", frob);
    return 0;
}

A = [[2,1],[1,3]]

tr(A)       = 5.0
λ1 + λ2     = 5.0000  (trace = sum of eigenvalues)

det(A)      = 5.0
λ1 × λ2     = 5.0000  (det = product of eigenvalues)

tr(AB) = 47.0, tr(BA) = 47.0  (equal even though AB ≠ BA!)

||A||_F = sqrt(tr(A^T A)) = 3.8730

