    printf("2.0 * x  = [%.0f, %.0f, %.0f]\n", y[0], y[1], y[2]);

    scalar_mult(y, -0.5, x, 3);
    printf("-0.5 * x = [%.1f, %.1f, %.1f]\n", y[0], y[1], y[2]);
