                  4, 5, 6};
    double At[6];
    transpose(At, A, 2, 3);

    print_matrix("A", A, 2, 3);
    print_matrix("A^T", At, 3, 2);

    double S[] = 

    print_matrix("S (symmetric)", S, 2, 2);
    printf("Symmetric? %s\n", is_symmetric(S, 2) ? "Yes" : "No");
    return 0;
}

