2.4 范数\[\|\mathbf{x}\|_p = \left( \sum_{i=1}^n |x_i|^p \right)^{1/p}\]| \(p\) | 名称 | 公式 | 几何意义 || — | — | — | — || \(p=1\) | L1 范数 | \(\sum \vert x_i \vert\) | 曼哈顿距离 || \(p=2\) | L2 范数（欧几里得） | \(\sqrt{\sum x_i^2}\) | 直线距离 || \(p=\infty\) | L∞ 范数 | \(\max_i \vert x_i \vert\) | 最大分量 |L2 范数的简写：\[\|\mathbf{x}\| = \|\mathbf{x}\|_2 = \sqrt{\mathbf{x}^T \mathbf{x}}\]矩阵范数（Frobenius）：\[\|A\|_F = \sqrt{\sum_{i=1}^m \sum_{j=1}^n a_{ij}^2} = \sqrt{\text{trace}(A^T A)}\]在深度学习中的角色：权重衰减 \(= \frac{\lambda}{2} \|W\|_F^2\)#### 代码表示：L1/L2/L∞范数与 Frobenius 范数练习：实现 norm_l1、norm_l2、norm_linf 和 frobenius_norm。计算 \(\mathbf{x} = [3, 4]\) 的三种范数和 \(A_{2\times 3}\) 的 Frobenius 范数。

#include &lt;stdio.h&gt;
#include &lt;math.h&gt;

double dot(const double* x, const double* y, int n) {
    double s = 0.0;
    for (int i = 0; i &lt; n; i++) s += x[i] * y[i];
    return s;
}

double norm_l1(const double* x, int n) {
    double s = 0.0;
    for (int i = 0; i &lt; n; i++) s += fabs(x[i]);
    return s;
}

double norm_l2(const double* x, int n) {
    return sqrt(dot(x, x, n));
}

double norm_linf(const double* x, int n) {
    double mx = 0.0;
    for (int i = 0; i &lt; n; i++)
        if (fabs(x[i]) &gt; mx) mx = fabs(x[i]);
    return mx;
}

double frobenius_norm(const double* A, int m, int n) {
    double s = 0.0;
    for (int i = 0; i &lt; m * n; i++) s += A[i] * A[i];
    return sqrt(s);
}

int main() {
    double x[] = {3.0, 4.0};
    printf("x = [3, 4]\n");
    printf("||x||_1   = %.2f  (Manhattan)\n", norm_l1(x, 2));
    printf("||x||_2   = %.2f  (Euclidean)\n", norm_l2(x, 2));
    printf("||x||_inf = %.2f  (Max)\n", norm_linf(x, 2));

    double A[] = {1, 2, 3, 4, 5, 6};  // 2×3
    printf("\nA = [[1,2,3],[4,5,6]]\n");
    printf("||A||_F   = %.4f\n", frobenius_norm(A, 2, 3));
    return 0;
}

x = [3, 4]
||x||_1   = 7.00  (Manhattan)
||x||_2   = 5.00  (Euclidean)
||x||_inf = 4.00  (Max)

A = [[1,2,3],[4,5,6]]
||A||_F   = 9.5394

